const rateLimit = require('express-rate-limit');

const app = express();
const PORT = process.env.PORT || 3000;

// Security headers
app.use(helmet());

// Rate limiting
const limiter = rateLimit({ windowMs: 60 * 1000, max: 100 });
app.use(limiter);

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// TODO: Add authentication middleware before exposing real user data
app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

**Install the new deps:**
```bash
npm install helmet express-rate-limit
```

---

### Summary

| Severity | Issue | Recommendation |
|----------|-------|----------------|
| 🟡 Medium | No rate limiting | Add `express-rate-limit` |
| 🟡 Medium | No authentication on `/users` | Add auth middleware |
| 🟡 Medium | Missing security headers | Add `helmet` |
| 🟢 Low | Hardcoded port | Use `process.env.PORT` |

No critical vulnerabilities were found in the current code. The main risks are best-practice hardening items that become important as the app grows.

